\begin{tikzpicture}
\begin{axis}[
    ybar,
    ymin=0,
    bar width=0.17cm,
    height=3cm,
    width=.60\columnwidth,
    enlarge x limits=0.5,


    ylabel={recall (\%)},
    ylabel near ticks,
    symbolic x coords={strict,strict$@$10},
    xtick=data,
    ]


\addplot[magenta,fill=magenta]
    coordinates {
        (strict, 0.4)
        (strict$@$10, 0.4)
    }; \label{CWA-bar}

\addplot[blue,fill=blue] 
    coordinates {
        (strict, 0.1)
        (strict$@$10, 0.1)
    }; \label{negatertheta-bar}

\addplot[draw = black,line width = .2mm,fill = cyan,postaction={pattern=vertical lines}]  
    coordinates {
        (strict, 0.9)
        (strict$@$10, 0.9)
    }; \label{negaternabla-bar}

\addplot[black,fill=white,pattern=dots] 
    coordinates {
        (strict, 4.7)
        (strict$@$10, 4.8)
    }; \label{uncommonbase-bar}

\addplot[black,fill=white,pattern=horizontal lines] 
    coordinates {
        (strict, 4.7)
        (strict$@$10, 4.7)
    }; \label{uncommonstrict-bar}

\addplot[black,fill=white,pattern=north east lines] 
    coordinates {
        (strict, 4.9)
        (strict$@$10, 5.0)
    }; \label{uncommonrelaxed-bar}
\end{axis}
\end{tikzpicture}
